import { epochTogmt } from "src/utils/Common";
import { v4 as uuidv4 } from 'uuid';
import CopyPaymentLink from "../CopyPaymentLink";
import { Link } from "react-router-dom";

export const tableSignupUserListConstant = () => {
    return [

        {
            id: 1,
            name: "Email",
            cell: (row) => {
                return (
                    <Link to={`/member-details/${row?.userId}`}>
                        <span className="sub">{row.email}</span>
                    </Link>
                );
            }
        },
        {
            id: 2,
            name: "Signed up date",
            selector: (row) => row.createTime ? epochTogmt(row.createTime) : '-',
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 4,
            name: "First name",
            selector: (row) => row?.firstName ? row.firstName : '-',
            sortable: true,
            reorder: true,
        },
        {
            id: 5,
            name: "Last name",
            selector: (row) => row?.lastName ? row.lastName : '-',
            sortable: true,
            reorder: true,
        },
        {
            id: 6,
            name: "Phone number",
            selector: (row) => row?.phone ? row.phone : '-'
        },
    ];
};
